import React, { useState, useEffect } from 'react';
import { Check, Plus, Trash2, Trophy, RotateCcw } from 'lucide-react';

export default function App() {
  const [habits, setHabits] = useState(() => {
    const saved = localStorage.getItem('daily-habits');
    return saved ? JSON.parse(saved) : [
      { id: 1, text: 'Morning Meditation', completed: false },
      { id: 2, text: 'Drink 2L Water', completed: false },
      { id: 3, text: 'Read 30 Minutes', completed: false },
      { id: 4, text: 'Workout', completed: false },
      { id: 5, text: 'Journaling', completed: false },
    ];
  });

  useEffect(() => {
    localStorage.setItem('daily-habits', JSON.stringify(habits));
  }, [habits]);

  const toggleHabit = (id) => {
    setHabits(habits.map(h => h.id === id ? { ...h, completed: !h.completed } : h));
  };

  const progress = Math.round((habits.filter(h => h.completed).length / habits.length) * 100);

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 p-4 md:p-8 font-sans">
      <div className="max-w-md mx-auto">
        <header className="mb-8 text-center">
          <h1 className="text-3xl font-bold bg-gradient-to-r from-indigo-400 to-cyan-400 bg-clip-text text-transparent">HabitFlow</h1>
          <p className="text-slate-400 mt-2">Daily progress tracker</p>
        </header>

        <div className="bg-slate-900 border border-slate-800 rounded-2xl p-6 mb-8 shadow-2xl">
          <div className="flex justify-between items-end mb-2">
            <span className="text-sm font-medium text-slate-400">Daily Goal</span>
            <span className="text-2xl font-bold text-indigo-400">{progress}%</span>
          </div>
          <div className="w-full bg-slate-800 h-3 rounded-full overflow-hidden">
            <div 
              className="h-full bg-gradient-to-r from-indigo-500 to-cyan-500 transition-all duration-500" 
              style={{ width: `${progress}%` }}
            />
          </div>
        </div>

        <div className="space-y-3">
          {habits.map((habit) => (
            <div 
              key={habit.id}
              onClick={() => toggleHabit(habit.id)}
              className={`group flex items-center p-4 rounded-xl border transition-all duration-200 cursor-pointer ${
                habit.completed 
                  ? 'bg-indigo-900/20 border-indigo-500/50' 
                  : 'bg-slate-900 border-slate-800 hover:border-slate-700'
              }`}
            >
              <div className={`w-6 h-6 rounded-md border flex items-center justify-center transition-colors ${
                habit.completed ? 'bg-indigo-500 border-indigo-500' : 'border-slate-600'
              }`}>
                {habit.completed && <Check size={14} className="text-white" />}
              </div>
              <span className={`ml-4 font-medium ${habit.completed ? 'text-slate-300 line-through' : 'text-slate-100'}`}>
                {habit.text}
              </span>
            </div>
          ))}
        </div>

        <button 
          onClick={() => setHabits(habits.map(h => ({ ...h, completed: false })))}
          className="w-full mt-8 py-3 flex items-center justify-center gap-2 text-slate-400 hover:text-white transition-colors"
        >
          <RotateCcw size={18} />
          Reset for Tomorrow
        </button>
      </div>
    </div>
  );
}
